import (
	context "context"
	fern "github.com/extra-properties/fern"
	fernclient "github.com/extra-properties/fern/client"
)

client := fernclient.NewClient()
response, err := client.User.Createuser(
	context.TODO(),
	&fern.UserCreateUserRequest{
		Type:    fern.UserCreateUserRequestTypeCreateUserRequest,
		Version: fern.UserCreateUserRequestVersionV1,
		Name:    "name",
	},
)
